160	
161	  // ---------- Modifier scope on multi-item policies ----------
162	  it.todo("cursed sword + plain amulet → 100 + 60 + 50 curse = 210 G + 10 first ins on sword + 6 first ins on amulet + 5 fee");
163	  it.todo("first insurance surcharge applies per item, not per policy");
164	
165	  // ---------- Rounding in MHPCO's favor ----------
166	  it.todo("premium calculation yielding 197.5 G → rounded up to 198 G");
167	  it.todo("payout calculation yielding 350.5 G → rounded down to 350 G");
168	
169	  // ---------- Integration premium examples ----------
170	  it.todo("newcomer with cursed sword (steel, enchantment 3) → premium 165 G");
171	  it.todo("long-standing (3y) customer's second contract: cursed sword enchantment 7 → premium 160 G");
172	
173	  // ---------- Claims: simple cases ----------
174	  it.todo("regular sword (steel, enchantment 3), damage 500 → payout 400 G (full minus deductible)");
175	  it.todo("damage to a rune (insurance value 250), damage 200 → payout 100 G (full minus deductible)");
176	
177	  // ---------- Claims: special clauses ----------
178	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700 G (dragon: full, minus deductible)");
179	  it.todo("steel sword enchantment 9, damage 1000 → payout 400 G (50% then deductible)");
180	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400 G (50% wins, then deductible)");
181	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400 G (high-enchantment then deductible)");
182	
183	  // ---------- Claims: deductible per damage event ----------
184	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible applies per item)");
185	
186	  // ---------- Claims: cap ----------
