198	  it.todo("quote with unknown item type → CLI exits non-zero, error to stderr, no results on stdout");
199	  it.todo("claim references damage entry whose item is not part of policy → CLI exits non-zero");
200	  it.todo("claim with damage entry of unknown item type → CLI exits non-zero");
201	  it.todo("claim with negative damage amount → CLI exits non-zero");
202	
203	  // ---------- CLI / multi-step scenario ----------
204	  it.todo("scenario with quote then claim returns results array of matching length and order");
205	  it.todo("claim's policy field references quote step by zero-based index");
