1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	const CURSE_SURCHARGE_RATE = 0.5;
9	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
10	const HIGH_ENCHANTMENT_THRESHOLD = 5;
11	const LOYALTY_DISCOUNT_RATE = 0.2;
12	const LOYALTY_THRESHOLD_YEARS = 2;
13	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
14	const BASE_PREMIUMS: Record<string, number> = {
15	  sword: 100,
16	  amulet: 60,
17	  staff: 80,
18	  potion: 40,
19	  rune: 25,
20	  moonstone: 25,
21	};
22	
23	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
24	const BLOCK_SIZE = 3;
25	const BLOCK_BASE_PREMIUM = 60;
26	
27	const unitBasePremium = (type: string): number => BASE_PREMIUMS[type] ?? 0;
28	
29	const isComponentBlock = (type: string, count: number): boolean =>
30	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
31	
32	const groupBasePremium = (type: string, count: number): number =>
33	  isComponentBlock(type, count) ? BLOCK_BASE_PREMIUM : count * unitBasePremium(type);
34	
35	const countByType = (items: Item[]): Map<string, number> =>
36	  items.reduce(
37	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
38	    new Map<string, number>(),
39	  );
40	
41	const itemsBasePremium = (items: Item[]): number =>
42	  [...countByType(items)].reduce(
43	    (total, [type, count]) => total + groupBasePremium(type, count),
44	    0,
45	  );
46	
47	const itemModifierSurcharge = (item: Item): number => {
48	  const base = unitBasePremium(item.type);
49	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
50	  const highEnchantmentSurcharge =
51	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
52	  return curseSurcharge + highEnchantmentSurcharge;
53	};
54	
55	const itemsModifierSurcharge = (items: Item[]): number =>
56	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
57	
58	const loyaltyDiscount = (base: number, customer: Customer): number =>
59	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
60	
61	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
62	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
63	
64	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
65	  const base = itemsBasePremium(items);
66	  const modifierSurcharge = itemsModifierSurcharge(items);
67	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
68	  const discount = loyaltyDiscount(base, customer) + followUpDiscount(base, isFollowUp);
69	  return Math.ceil(base + modifierSurcharge + firstInsuranceSurcharge - discount + PROCESSING_FEE);
70	};
71	
72	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
73	  let quoteCount = 0;
74	  const results = scenario.steps.map((step) => {
75	    const isFollowUp = quoteCount > 0;
76	    quoteCount += 1;
77	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
78	  });
79	  return { results };
80	};
